pragma cashscript 0.11.5;

contract TapToPay(bytes20 backendPkh, bytes category) {

    function spend(
        bytes merchantId, 
        sig merchantSig, 
        pubkey merchantPk, 
        sig backendSig, 
        pubkey backendPk) {

        /**
            inputs:
                - [0] OwnershipNFT[category]: from contract
                - [1] MerchantAuthNFT (MerchantAuthNFT.tokenCategory == OwnershipNFT[category].nftCommitment): from contract
                - [2+] BCH UTXOs : from contract
            outputs:
                - [0] OwnershipNFT[category] : to contract
                - [1] MerchantAuthNFT: to contract
                - [2] Send amount: to merchant
                - [3] Change amount: to contract (Optional)
         */

        require(hash160(backendPk) == backendPkh, 'Invalid backend public key hash');
        require(checkSig(backendSig, backendPk), 'Invalid backend signature');
        require(checkSig(merchantSig, merchantPk), 'Invalid merchant signature');

        require(tx.inputs.length >= 3, 'Unexpected number of inputs, must be at least 3');
        require(tx.outputs.length >= 3 && tx.outputs.length <= 4, 'Unexpected number of outputs, must be 3 to 4');

        // OwnershipNFT[category].tokenCategory must match category
        bytes ownershipCategory = (tx.inputs[0].tokenCategory).split(32)[0];
        require(ownershipCategory == category, 'Invalid contract auth token category'); 

        // MerchantAuthNFT.tokenCategory must match OwnershipNFT[category].nftCommitment
        bytes expectedAuthCategory = tx.inputs[0].nftCommitment.split(1)[1];
        bytes merchantCategory = (tx.inputs[1].tokenCategory).split(32)[0];
        require(merchantCategory == expectedAuthCategory, 'Invalid merchant token category'); 

        // Parse the commitment of the merchant auth NFT
        bytes commitment = tx.inputs[1].nftCommitment;
        bytes authFlag, bytes rest = commitment.split(1); // (1 byte) authFlag = 0x00 (not authorized) | 0x01 (authorized)
        bytes spendLimit, bytes expectedMerchantHash = rest.split(8); // (8 bytes) spendLimit in satoshis, (remaining bytes) expectedMerchantHash
        bytes fullHash = sha256(merchantId + merchantPk);
        bytes merchantHash = fullHash.split(31)[0];

        int actualSendAmount = tx.outputs[2].value;
        bool isAuthorized = authFlag == 0x01;
        bool isGlobalAuth = expectedMerchantHash == 0x;
        bool isMerchantAuth = merchantHash == expectedMerchantHash;
        bool isSendAmountWithinLimit = actualSendAmount <= int(spendLimit);

        require(isAuthorized, 'Access denied: Merchant is not authorized');
        require(isGlobalAuth || isMerchantAuth, 'Access denied: Invalid global auth or merchant hash');
        require(isSendAmountWithinLimit, 'Send amount exceeds spend limit');

        // Require that the NFTs are sent back to this contract
        require(tx.outputs[0].tokenCategory.split(32)[0] == category, 'Ownership NFT must send back to this contract');
        require(tx.outputs[1].tokenCategory.split(32)[0] == expectedAuthCategory, 'Auth NFT must send back to this contract');
        require(
            tx.outputs[0].lockingBytecode == tx.inputs[0].lockingBytecode &&
            tx.outputs[1].lockingBytecode == tx.inputs[1].lockingBytecode,
            'NFTs must send back to this contract'
        );

        // Require that the commitments of the NFTs do not change
        require(tx.outputs[0].nftCommitment == tx.inputs[0].nftCommitment, 'Ownership NFT commitment must not change');
        require(tx.outputs[1].nftCommitment == tx.inputs[1].nftCommitment, 'Auth NFT commitment must not change');
    }

    /**
    * @notice Set the owner of the contract
    * @param authCategory The category of the auth token
    * @param ownerPk The public key of the new owner
    * @param ownerSig The signature of the new owner
    * @inputs:
    *   - [0] OwnershipNFT[pkh]: from contract
    *   - [1] OwnershipNFT[category]: from contract
    *   - [2] LinkingNFT: from caller
    * @outputs:
    *   - [0] OwnershipNFT[pkh]: back to contract (now holds the owner's public key)
    *   - [1] OwnershipNFT[category]: back to contract (now holds the auth tokenid)
    */
    function setOwner(bytes authCategory, pubkey ownerPk, sig ownerSig) {
        /**
            inputs: 
                - [0] Contract's owner NFT (commitment = 0x0<xcategory>)
                - [1] Contract's auth NFT (commitment = 0x1<xcategory>)
                - [2] Caller's NFT (category=xcategory)

            outputs:
                - [0] Contract's owner NFT (now should hold the owner's public key)
                - [1] Contract's auth NFT (now should hold the auth tokenid)
         */ 
        require(checkSig(ownerSig, ownerPk), 'Invalid signature');
        require(tx.inputs.length >= 4, 'Must have at least 4 inputs');
        require(tx.outputs.length >= 3, 'Must have at least 3 outputs');

        bytes inputTokenCategory0 = tx.inputs[0].tokenCategory.split(32)[0];
        bytes inputTokenCategory1 = tx.inputs[1].tokenCategory.split(32)[0];

        require(
            inputTokenCategory0 == category && 
            inputTokenCategory1 == category, 
            'Inputs 1 and 2 must be contract tokens'
        );

        bytes xcategory = tx.inputs[2].tokenCategory.split(32)[0];
        bytes pkh_key, bytes pkh_rest = tx.inputs[0].nftCommitment.split(1);
        bytes pkh_xcategory = pkh_rest.split(32)[0];

        bytes auth_key, bytes auth_rest = tx.inputs[1].nftCommitment.split(1);
        bytes auth_xcategory = auth_rest.split(32)[0];

        require(
            pkh_key == 0x00 && 
            auth_key == 0x01,
            "Inputs do not have expected keys in commitments (0x00 for owner, 0x01 for auth)"
        );

        require(
            pkh_xcategory == xcategory && 
            auth_xcategory == xcategory, 
            'Input 3 category does not match the expected category of inputs 1 and 2'
        );

        bytes outputTokenCategory0 = tx.outputs[0].tokenCategory.split(32)[0];
        bytes outputTokenCategory1 = tx.outputs[1].tokenCategory.split(32)[0];

        require(
            outputTokenCategory0 == category && 
            outputTokenCategory1 == category,
            'Outputs do not have expected token category'
        );

        bytes xpkh_commitment = 0x00 + hash160(ownerPk);
        bytes xauth_commitment = 0x01 + authCategory;

        require(
            tx.outputs[0].nftCommitment == xpkh_commitment && 
            tx.outputs[1].nftCommitment == xauth_commitment,
            'Outputs do not have expected commitments'
        );
    }

    /**
    * @notice Mutate the contract's auth tokens
    * @param ownerPk The public key of the owner
    * @param ownerSig The signature of the owner
    * @inputs:
    *   - [0] OwnershipNFT[pkh]: from contract
    *   - [1] OwnershipNFT[category]: from contract
    *  - [2+] AuthNFTs: from contract
    * @outputs:
    *   - [0] OwnershipNFT[pkh]: back to contract
    *   - [1] OwnershipNFT[category]: back to contract
    *  - [2+] AuthNFTs: back to contract
     */
    function mutate(pubkey ownerPk, sig ownerSig) {
        require(checkSig(ownerSig, ownerPk), 'Invalid owner signature');

        if (this.activeInputIndex < 2) {
            bool isValidOwnership = (
                tx.inputs[0].tokenCategory.split(32)[0] == category && 
                tx.inputs[1].tokenCategory.split(32)[0] == category
            );
            bool isValidOwner = hash160(ownerPk) == tx.inputs[0].nftCommitment.split(1)[1];
            bool ownershipTokensReturned = (
                tx.outputs[0].tokenCategory.split(32)[0] == category &&
                tx.outputs[1].tokenCategory.split(32)[0] == category &&
                tx.outputs[0].lockingBytecode == tx.inputs[0].lockingBytecode &&
                tx.outputs[1].lockingBytecode == tx.inputs[1].lockingBytecode
            );
            bool ownershipTokensUnchanged = (
                tx.outputs[0].nftCommitment == tx.inputs[0].nftCommitment && 
                tx.outputs[1].nftCommitment == tx.inputs[1].nftCommitment
            );

            require(isValidOwnership, 'Invalid ownership NFT categories');
            require(isValidOwner, 'Invalid owner of the ownership NFT');
            require(ownershipTokensReturned, 'Ownership tokens must be sent back to contract');
            require(ownershipTokensUnchanged, 'Ownership token commitments must not change');
        } else {
            // must be mutating the contract's auth tokens
            bytes expectedCategory = tx.inputs[1].nftCommitment.split(1)[1];
            require(tx.inputs[this.activeInputIndex].tokenCategory.split(32)[0] == expectedCategory, 'Mutated input must have the expected category');
            require(tx.outputs[this.activeInputIndex].tokenCategory.split(32)[0] == expectedCategory, 'Mutated output must have the expected category');

            // mutated auth tokens must be returned to the contract
            require(
                tx.outputs[this.activeInputIndex].lockingBytecode == tx.inputs[this.activeInputIndex].lockingBytecode,
                'Mutated auth token must be sent back to contract'
            );
        }
    }

    /**
    * @notice Sweep the funds out of the contract
    * @param ownerPk The public key of the owner
    * @param ownerSig The signature of the owner
    * @inputs:
    *   - [0] OwnershipNFT[pkh]: from contract
    *   - [1+] BCH UTXOs : from contract
    * @outputs:
    *   - [0] OwnershipNFT[pkh]: back to contract
    *   - [1+] BCH UTXOs : to owner
    */
    function sweep(pubkey ownerPk, sig ownerSig) {
        require(checkSig(ownerSig, ownerPk), 'Invalid owner signature');

        if (this.activeInputIndex == 0) {
            bool isCorrectOwnership = tx.inputs[0].tokenCategory.split(32)[0] == category;
            bool isCorrectOwner = hash160(ownerPk) == tx.inputs[0].nftCommitment.split(1)[1];
            bool ownershipReturned = (
                tx.outputs[0].tokenCategory.split(32)[0] == category &&
                tx.outputs[0].lockingBytecode == tx.inputs[0].lockingBytecode
            );
            bool ownershipUnchanged = tx.outputs[0].nftCommitment == tx.inputs[0].nftCommitment;

            require(isCorrectOwnership, 'Invalid ownership NFT category');
            require(isCorrectOwner, 'Invalid owner of the ownership NFT');
            require(ownershipReturned, 'Ownership NFT must be sent back to contract');
            require(ownershipUnchanged, 'Ownership NFT commitment must not change');
        } else {
            // v1: BCH-only sweep. FT support reserved for a future contract version
            require(tx.inputs[this.activeInputIndex].tokenCategory == 0x, 'Swept input must not be an NFT');
            require(tx.outputs[this.activeInputIndex].tokenCategory == 0x, 'Swept output must not be an NFT');
        }
    }
}
